    it('should return to flow', () => {
      setprevail('task');
      unsetprevail();
      expect(isPrevailing()).toBe(false);
      expect(prev().mode).toBe('flow');
    });
  });

  describe('log() - history navigation', () => {
    it('should record mode transitions', () => {
      prev(true);
      prev(2);
